**Summary:** Google Chat approval-card text was truncated with a raw UTF-16 slice, so an emoji near the limit became a lone surrogate in the `cardsV2` API payload. This uses `truncateUtf16Safe` to truncate on a code-point boundary.

## What Problem This Solves

Google Chat approval cards truncated long text by UTF-16 code unit length. When the truncation boundary landed inside an astral character, such as a command containing `1796` `a` characters followed by `😀`, the old raw `.slice()` behavior kept only the high surrogate (`0xd83d`) before appending `...`.

That produced ill-formed UTF-16 in the Google Chat card text. The terminal proof below reproduces the old boundary with raw `.slice()` and shows `encodeURIComponent` rejecting the result with `URIError: URI malformed`.

## Fix

`extensions/googlechat/src/approval-handler.runtime.ts` now routes Google Chat approval text truncation through the shared `truncateUtf16Safe` helper before appending the suffix.

The helper clamps and floors the requested length, slices through the shared UTF-16-safe path, and adjusts slice edges away from dangling high/low surrogate halves. Google Chat still escapes plain command/card text after truncation, so the final card text remains both HTML-escaped and UTF-16 well formed.

## Evidence

The demo imports the real Google Chat approval runtime from `extensions/googlechat/src/approval-handler.runtime.ts` and calls `googleChatApprovalNativeRuntime.presentation.buildPendingPayload` with an emoji/surrogate-boundary command. The `BEFORE` section uses the old raw `.slice()` shape for comparison; the `AFTER` section reads the actual fixed Google Chat card text.

Command:

```bash
node --import tsx demo.mts
```

Output:

```text
input.length 1898
emoji boundary codePointAt(1796) 0x1f600
BEFORE raw slice length 1800
BEFORE codePointAt(1796) 0xd83d
BEFORE lone-surrogate-hex 0xd83d
BEFORE lone-surrogate true
BEFORE encodeURIComponent URIError: URI malformed
AFTER source googleChatApprovalNativeRuntime.presentation.buildPendingPayload
AFTER fixed card text length 1799
AFTER tail "aaaaa..."
AFTER codePointAt(1796) 0x2e
AFTER lone-surrogate-hex none
AFTER lone-surrogate false
AFTER encodeURIComponent aaaaaaaaa...
```

The fixed runtime output has `lone-surrogate false`, no dangling surrogate hex value, and survives URI encoding, so the Google Chat approval card text is well formed at the emoji truncation boundary.

## Tests

Vitest regression coverage in `extensions/googlechat/src/approval-handler.runtime.test.ts` covers the red/green behavior for Google Chat approval card truncation:

- `keeps truncated pending command card text UTF-16 well formed` covers the exact boundary where raw truncation would leave `\ud83d`.
- `preserves a complete astral character when it fits before the truncation suffix` covers the adjacent case where the complete emoji should be retained before `...`.
```
diff --git a//tmp/proof-wt-96573/demo.mts b//tmp/proof-wt-96573/demo.mts
new file mode 100644
index 00000000000000000000…[40 ×'0' elided]..cecdad8f7107d3ca76513278da79a1e1419a0dc3
--- /dev/null
+++ b//tmp/proof-wt-96573/demo.mts
@@ -0,0 +1,152 @@
+import type { ExecApprovalPendingView } from "openclaw/plugin-sdk/approval-handler-runtime";
+import type { OpenClawConfig } from "openclaw/plugin-sdk/config-contracts";
+import { googleChatApprovalNativeRuntime } from "./extensions/googlechat/src/approval-handler.runtime.ts";
+import type { ResolvedGoogleChatAccount } from "./extensions/googlechat/src/accounts.ts";
+
+const loneSurrogatePattern =
+  /[\uD800-\uDBFF](?![\uDC00-\uDFFF])|(?<![\uD800-\uDBFF])[\uDC00-\uDFFF]/u;
+
+function firstLoneSurrogateHex(value: string): string | null {
+  for (let index = 0; index < value.length; index += 1) {
+    const codeUnit = value.charCodeAt(index);
+    if (codeUnit >= 0xd800 && codeUnit <= 0xdbff) {
+      const nextCodeUnit = index + 1 < value.length ? value.charCodeAt(index + 1) : -1;
+      if (nextCodeUnit < 0xdc00 || nextCodeUnit > 0xdfff) {
+        return `0x${codeUnit.toString(16)}`;
+      }
+      index += 1;
+      continue;
+    }
+    if (codeUnit >= 0xdc00 && codeUnit <= 0xdfff) {
+      return `0x${codeUnit.toString(16)}`;
+    }
+  }
+  return null;
+}
+
+function formatCodePointAtBoundary(value: string, index: number): string {
+  const codePoint = value.codePointAt(index);
+  return codePoint == null ? "none" : `0x${codePoint.toString(16)}`;
+}
+
+function getTextParagraphText(payload: {
+  cardsV2: Array<{
+    card: {
+      sections?: Array<{
+        header?: string;
+        widgets?: Array<{ textParagraph?: { text: string } }>;
+      }>;
+    };
+  }>;
+}): string {
+  const text = payload.cardsV2[0]?.card.sections?.find((section) => section.header === "Command")
+    ?.widgets?.[0]?.textParagraph?.text;
+  if (typeof text !== "string") {
+    throw new Error("Expected Google Chat Command text paragraph");
+  }
+  return text;
+}
+
+const account = {
+  accountId: "default",
+  enabled: true,
+  credentialSource: "inline",
+  config: {
+    audienceType: "app-url",
+    audience: "https://chat-app.example.test/googlechat",
+    appPrincipal: "123456789012345678901",
+  },
+} as ResolvedGoogleChatAccount;
+
+const cfg: OpenClawConfig = {
+  channels: {
+    googlechat: {
+      serviceAccount: {
+        type: "service_account",
+        client_email: "bot@example.com",
+        private_key: "test-key",
+        token_uri: "https://oauth2.googleapis.com/token",
+      },
+      audienceType: "app-url",
+      audience: "https://chat-app.example.test/googlechat",
+      appPrincipal: "123456789012345678901",
+      dm: { allowFrom: ["users/123"] },
+    },
+  },
+};
+
+const commandText = `${"a".repeat(1796)}${String.fromCodePoint(0x1f600)}${"b".repeat(100)}`;
+const oldTruncated = `${commandText.slice(0, 1797)}...`;
+const view: ExecApprovalPendingView = {
+  approvalId: "approval-1",
+  approvalKind: "exec",
+  phase: "pending",
+  title: "Exec Approval Required",
+  description: "A command needs your approval.",
+  metadata: [],
+  ask: "on-miss",
+  agentId: "main",
+  warningText: null,
+  commandAnalysis: null,
+  commandText,
+  commandPreview: null,
+  cwd: "/tmp",
+  envKeys: [],
+  host: "gateway",
+  nodeId: null,
+  sessionKey: "agent:main:googlechat:spaces/AAA",
+  actions: [
+    {
+      kind: "decision",
+      decision: "allow-once",
+      label: "Allow Once",
+      style: "success",
+      command: "/approve approval-1 allow-once",
+    },
+    {
+      kind: "decision",
+      decision: "deny",
+      label: "Deny",
+      style: "danger",
+      command: "/approve approval-1 deny",
+    },
+  ],
+  expiresAtMs: Date.now() + 60_000,
+};
+
+const nowMs = Date.now();
+const pendingPayload = await googleChatApprovalNativeRuntime.presentation.buildPendingPayload({
+  cfg,
+  accountId: "default",
+  context: { account },
+  request: {
+    id: view.approvalId,
+    request: { command: view.commandText },
+    createdAtMs: nowMs,
+    expiresAtMs: view.expiresAtMs,
+  },
+  approvalKind: "exec",
+  nowMs,
+  view,
+});
+const fixedTruncated = getTextParagraphText(pendingPayload);
+
+console.log("input.length", commandText.length);
+console.log("emoji boundary codePointAt(1796)", formatCodePointAtBoundary(commandText, 1796));
+console.log("BEFORE raw slice length", oldTruncated.length);
+console.log("BEFORE codePointAt(1796)", formatCodePointAtBoundary(oldTruncated, 1796));
+console.log("BEFORE lone-surrogate-hex", firstLoneSurrogateHex(oldTruncated) ?? "none");
+console.log("BEFORE lone-surrogate", loneSurrogatePattern.test(oldTruncated));
+try {
+  encodeURIComponent(oldTruncated);
+  console.log("BEFORE encodeURIComponent", "ok");
+} catch (error) {
+  console.log("BEFORE encodeURIComponent", error instanceof URIError ? "URIError: URI malformed" : String(error));
+}
+console.log("AFTER source", "googleChatApprovalNativeRuntime.presentation.buildPendingPayload");
+console.log("AFTER fixed card text length", fixedTruncated.length);
+console.log("AFTER tail", JSON.stringify(fixedTruncated.slice(-8)));
+console.log("AFTER codePointAt(1796)", formatCodePointAtBoundary(fixedTruncated, 1796));
+console.log("AFTER lone-surrogate-hex", firstLoneSurrogateHex(fixedTruncated) ?? "none");
+console.log("AFTER lone-surrogate", loneSurrogatePattern.test(fixedTruncated));
+console.log("AFTER encodeURIComponent", encodeURIComponent(fixedTruncated).slice(-12));

